import React, { useEffect, useState } from "react";
import Slider from "react-slick";
import axios from "axios";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

const ImageCarousel = () => {
  const [images, setImages] = useState([]);

  useEffect(() => {
    const fetchImages = async () => {
      try {
        const res = await axios.get("http://localhost:5000/api/gallery"); // Fetch images from backend
        setImages(res.data);
      } catch (error) {
        console.error("Error fetching images", error);
      }
    };
    fetchImages();
  }, []);

  const settings = {
    dots: false,
    infinite: true,
    speed: 700,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
    arrows: true,
  };

  return (
    <div className="w-full mx-auto mt-6">
      <Slider {...settings}>
        {images.length > 0 ? (
          images.map((img, index) => (
            <div key={index}>
              <img
                src={`http://localhost:5000${img.imageUrl}`} // ✅ Fetching from backend
                alt={img.title}
                className="w-full h-[500px] object-cover rounded-lg"
              />
            </div>
          ))
        ) : (
          <div className="flex justify-center items-center h-[500px] text-gray-500">
            No images available
          </div>
        )}
      </Slider>
    </div>
  );
};

export default ImageCarousel;
